 32→/// Install configured packages inside a container via `apt-get`.
 33→///
 34→/// `cli` is the container CLI binary name (e.g. `"docker"` or `"container"`).
 35→async fn provision_packages(cli: &str, container_name: &str, packages: &[String]) -> Result<()> {
 36→    if packages.is_empty() {
 37→        return Ok(());
 38→    }
 39→    let pkg_list = packages.join(" ");
 40→    info!(container = container_name, packages = %pkg_list, "provisioning sandbox packages");
 41→    let output = tokio::process::Command::new(cli)
 42→        .args([
 43→            "exec",
 44→            container_name,
 45→            "sh",
 46→            "-c",
 47→            &format!("apt-get update -qq && apt-get install -y -qq {pkg_list} 2>&1 | tail -5"),
 48→        ])
 49→        .output()
 50→        .await?;
 51→    if !output.status.success() {
 52→        let stderr = String::from_utf8_lossy(&output.stderr);
 53→        warn!(
 54→            container = container_name,
 55→            %stderr,
 56→            "package provisioning failed (non-fatal)"
 57→        );
 58→    }
 59→    Ok(())
 60→}
